"use strict";(self.webpackChunkdocusaurus_temp=self.webpackChunkdocusaurus_temp||[]).push([[5798],{2739:(a,i,n)=>{n.r(i),n.d(i,{assets:()=>h,contentTitle:()=>t,default:()=>d,frontMatter:()=>s,metadata:()=>r,toc:()=>u});const r=JSON.parse('{"id":"quick-start/part3-finance","title":"3-qism: Pullar","description":"\\"Ushbu qo\u2018llanmaning bu bo\u2018limida siz moliyani qanday boshqarish va hisobotlar yordamida biznesni tahlil qilishni o\u2018rganasiz.","source":"@site/i18n/uz/docusaurus-plugin-content-docs/current/quick-start/part3-finance.md","sourceDirName":"quick-start","slug":"/quick-start/part3-finance","permalink":"/uz/docs/quick-start/part3-finance","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":4,"frontMatter":{"id":"part3-finance","title":"3-qism: Pullar","sidebar_label":"3-qism: Pullar","sidebar_position":4},"sidebar":"tutorialSidebar","previous":{"title":"2-qism: Mahsulotlar va mijozlar","permalink":"/uz/docs/quick-start/part2-setup"},"next":{"title":"Tizim bilan ishlash bo\u2018yicha yo\u2018riqnomalar","permalink":"/uz/docs/knowledge/"}}');var l=n(4848),o=n(8453);const s={id:"part3-finance",title:"3-qism: Pullar",sidebar_label:"3-qism: Pullar",sidebar_position:4},t="3-qism. Pullar va hisobotlar",h={},u=[];function m(a){const i={h1:"h1",header:"header",li:"li",p:"p",ul:"ul",...(0,o.R)(),...a.components};return(0,l.jsxs)(l.Fragment,{children:[(0,l.jsx)(i.header,{children:(0,l.jsx)(i.h1,{id:"3-qism-pullar-va-hisobotlar",children:"3-qism. Pullar va hisobotlar"})}),"\n",(0,l.jsx)(i.p,{children:'"Ushbu qo\u2018llanmaning bu bo\u2018limida siz moliyani qanday boshqarish va hisobotlar yordamida biznesni tahlil qilishni o\u2018rganasiz.\r\nMoliyani boshqarish\r\niBox\u2019da moliya bilan to\u2018g\u2018ri ishlashni boshlash uchun avvalo pul bo\u2018yicha boshlang\u2018ich qoldiqlarni kiritish kerak \u2014 ya\u2019ni kassalarda va hisoblarda qancha mablag\u2018 borligini ko\u2018rsatish lozim.\r\nMa\u2019lumotlarni oldindan Excel faylida yoki qo\u2018lda tayyorlab oling. Keyinchalik siz to\u2018lovlarni kiritishingiz va kassalar o\u2018rtasida pul o\u2018tkazishingiz mumkin bo\u2018ladi.\r\nPul qoldiqlarini qanday yuklash kerak\r\nKassalar yaratilganiga ishonch hosil qiling.\r\nPul \u2192 Balans korrektirovkalari\u2192 Kassa balansi korrektirovkalari bo\u2018limiga o\u2018ting.\r\nKassa balansi korrektirovkalari tugmasini bosing. Ma\u2019lumot kiritish oynasi ochiladi.\r\nKassa balansi korrektirovkalari\r\nKassani tanlang, sana, raqam va valyutani kiriting.\r\nKalkulyator tugmasini bosing \u2014 u sizga kerakli balansni hisoblab beradi. Summani kiriting va izoh qo\u2018shing, masalan: Boshlang\u2018ich qoldiq.\r\nKalkulyator\r\nSaqlash tugmasini bosing.\r\nOgohlantirishBoshlash vaqtidagi real qoldiqlarni kiriting \u2014 bu hisobotlarda chalkashliklarning oldini oladi va moliyaviy hisobni boshidan to\u2018g\u2018ri yuritishga yordam beradi.'}),"\n",(0,l.jsx)(i.p,{children:"Kirim va chiqimlarni kiritish\r\nKirimlar \u2014 mijoz buyurtma uchun to\u2018lov qilganda yoki avans berganda.Chiqimlar \u2014 ta\u2019mitnotchiga to\u2018lov qilganda, mijozga pul qaytarganda, ish haqi to\u2018langanda yoki boshqa xarajatlar rasmiylashtirilganda.\r\nMijozdan to\u2018lovni qanday rasmiylashtirish kerak:\r\nPul \u2192 Kirimlar bo\u2018limiga o\u2018ting.\r\nEkranning yuqori o\u2018ng burchagida plyus tugmasini bosing va Mijozdan to\u2018lovni tanlang.\r\nMijozdan to\u2018lovni bosing \u2014 ma\u2019lumot kiritish oynasi ochiladi.\r\nMijozdan to\u2018lovQuyidagilarni kiriting:\r\nMijoz\r\nShartnoma (agar mavjud bo\u2018lsa)\r\nMas\u2019ul shaxs\r\nSumma va valyuta\r\nPul tushgan kassa\r\nSotuvni bog\u2018lang \u2014 ushbu to\u2018lov qaysi sotuvga tegishli ekanini ko\u2018rsating.\r\nSotuvga bog\u2018lash\r\nZarur bo\u2018lsa, izoh qo\u2018shing.\r\nSaqlash tugmasini bosing.\r\nOgohlantirishHar doim to\u2018lovni aniq sotuvga bog\u2018lang \u2014 bu tizimga qarzdorliklarni to\u2018g\u2018ri hisoblashga yordam beradi va hisob-kitoblarda chalkashlikni oldini oladi.\r\nAgar mijoz turli valyutalardan foydalansa:\r\nMasalan, mijozning qarzi USD\u2019da bo\u2018lsa, ammo u UZS\u2019da to\u2018lasa, Summa maydonida UZS\u2019da olingan summani kiriting, Jami USD maydonida esa qarz valyutasini ko\u2018rsating.\r\nUZS\u2019dagi summa kassaga tushadi, USD\u2019dagi qarz esa kamayadi \u2014 iBox hammasini avtomatik qayta hisoblaydi."}),"\n",(0,l.jsx)(i.p,{children:"Kassadan kassaga pul o\u2018tkazish\r\nO\u2018tkazmalar bo\u2018limini oching.\r\nEkranning yuqori o\u2018ng burchagida Kassadan kassaga o\u2019tkazma \u2192 Qo\u2019shish tugmasini bosing.\r\nMa\u2019lumot kiritish oynasi ochiladi.\r\nPul o\u2018tkazish\r\nKassalarni, summani, valyutani va izohni kiriting.\r\nSaqlash tugmasini bosing."}),"\n",(0,l.jsx)(i.p,{children:"Mijozlar va ta\u2019minotchilar bo\u2018yicha boshlang\u2018ich balansni kiritish\r\nAgar tizim ishga tushirilayotgan paytda mijozlar yoki ta\u2019minotchilarning qarzlari mavjud bo\u2018lsa, ularni albatta qo\u2018lda kiriting \u2014 bu aniq hisob uchun zarur."}),"\n",(0,l.jsx)(i.p,{children:"Pullar \u2192 Balans korrektirovkalari moduliga o\u2018ting.\r\nYuqori o\u2018ng burchakda +  tugmasini bosing va Kontragent balansini tanlang."}),"\n",(0,l.jsx)(i.p,{children:"Ochilgan oynada quyidagilarni kiriting:\r\nKontragent (mijoz yoki ta\u2019minotchi)\r\nKorrektirovka sanasi va raqami\r\nValyuta va summa:"}),"\n",(0,l.jsxs)(i.ul,{children:["\n",(0,l.jsx)(i.li,{children:"\u2013 minus \u2014 bizga qarzdor"}),"\n",(0,l.jsxs)(i.li,{children:["\n",(0,l.jsxs)(i.ul,{children:["\n",(0,l.jsx)(i.li,{children:"plus \u2014 bizning kontragent oldidagi qarzimiz(kalkulyatorni bosing \u2014 u kerakli balansni hisoblab beradi)"}),"\n"]}),"\n"]}),"\n"]}),"\n",(0,l.jsx)(i.p,{children:"Zarur bo\u2018lsa, izoh qo\u2018shing, masalan: Boshlang\u2018ich qarz.\r\nSaqlash tugmasini bosing. Endi ushbu kontragent balansi barcha moliyaviy hisobotlarda hisobga olinadi."}),"\n",(0,l.jsx)(i.p,{children:"Excel orqali import qilish\r\nAgar mijozlar yoki ta\u2019minotchilar ko\u2018p bo\u2018lsa, boshlang\u2018ich qarzlarni Excel fayli orqali bitta ro\u2018yxat bilan yuklashingiz mumkin."}),"\n",(0,l.jsx)(i.p,{children:"Mijozlar bo\u2018limiga o\u2018ting.\r\nExcel\u2019dan import qilish tugmasini bosing.\r\nBoshlang\u2018ich balanslar bilan shablonni to\u2018ldiring. Agar ta\u2019minotchilarni yuklayotgan bo\u2018lsangiz, tizim ma\u2019lumotlarni avtomatik Ta\u2019minotchilar bo\u2018limiga o\u2018tkazishi uchun buni belgilang.\r\nFaylni yuklang.\r\nMaslahatBarcha kontragentlarda to\u2018g\u2018ri ma\u2019lumotlar kiritilganiga ishonch hosil qiling \u2014 bu qarzlarni hisobga olish uchun juda muhim."}),"\n",(0,l.jsx)(i.p,{children:"Boshlash uchun eng muhim hisobotlar\r\nHisobotlar biznesingizda nimalar bo\u2018layotganini tezda ko\u2018rishga yordam beradi. Tizim ma\u2019lumotlarni avtomatik yig\u2018adi va qulay ko\u2018rinishda taqdim etadi.\r\nHisobotlarni ochish uchun ekran chap tomonidagi modullar ro\u2018yxatini pastga aylantiring \u2014 bo\u2018lim eng oxirida joylashgan.\r\nHisobotlar\r\nSavdolar\r\nMahsulot bo\u2018yicha sotuvlar \u2014 qaysi Mahsulotlar eng ommabop va eng ko\u2018p daromad keltiradi.\r\nMahsulotlar bo\u2019yicha foyda \u2014 biznesingiz uchun eng foydali Mahsulotlar.\r\nXodimlar bo\u2018yicha foyda \u2014 har bir xodim qancha tushum keltiradi.\r\nMijozlar bo\u2018yicha foyda \u2014 qaysi mijozlar eng ko\u2018p foyda keltiradi.\r\nSotuvlar \u2014 ma\u2019lum davr ichidagi sotuvlar.\r\nMijozlar xaridlarini tahlili \u2014 kim tez-tez, kim kamroq xarid qiladi.\r\nMijozlardan qaytarishlar \u2014 qaysi Mahsulotlar ko\u2018proq qaytarilmoqda.\r\nOmbor\r\nOmborlar bo\u2018yicha qoldiqlar \u2014 har bir Mahsulotdan qancha qolgan va qaysi omborda.\r\nOmbor tahlili \u2014 qaysi mahsulot yaxshi sotilmoqda, qaysi turib qolgan. Umumiy va o\u2018rtacha tannarxni ko\u2018rish mumkin.\r\nSotish mumkin bo\u2019lgan qoldiq \u2014 allaqachon rezerv qilingan pozitsiyalarni hisobga olgan holda sotish mumkin bo\u2018lgan miqdor.\r\nTavsiya etilgan qoldiqlar \u2014 tizim qachon va qancha Mahsulot buyurtma berish kerakligini ko\u2018rsatadi.\r\nXaridlar\r\nXaridlar \u2014 qaysi va qancha Mahsulot sotib olinmoqda.\r\nTa\u2019minotchilarga qaytarishlar \u2014 qaytarilgan Mahsulotlar, sabablari va summalari.\r\nTa\u2019minotchilarga buyurtmalar \u2014 barcha buyurtmalar ro\u2018yxati.\r\nMoliyaviy hisobotlar\r\nKassa aylanmalari \u2014 kun, hafta yoki oy davomida qancha pul kirib-chiqqani.\r\nQarzdorlar ro\u2018yxati \u2014 qaysi mijozlar hali to\u2018lamagan va qancha qarzdor.\r\nFoyda va zararl \u2014 qancha daromad olingan, qanday xarajatlar bo\u2018lgan va sof foyda.\r\nOldo-berdi hisob-kitoblar \u2014 mijozlar, ta\u2019minotchilar va xodimlar bilan barcha pul operatsiyalari, jumladan ish haqi.\r\nSof aylanma kapital (SAK) \u2014 biznesni rivojlantirish uchun real mavjud erkin mablag\u2018.\r\nMaslahatHisobotlardan muntazam foydalaning \u2014 bu biznesingiz muvaffaqiyatining kalitidir."}),"\n",(0,l.jsx)(i.p,{children:'Biznes holatini tez baholash: Bosh panels bilan tanishuv\r\nDashing \u2014 iBox\u2019ning asosiy paneli bo\u2018lib, unda biznesingizning asosiy ko\u2018rsatkichlari qulay grafiklar va raqamlar ko\u2018rinishida jamlangan:\r\nSotuvlar \u2014 Kunlik sotuvlar jami va summasi\r\nEng Ko\u2019p Sotiladigan Mahsulotlar \u2014 savdo yetakchilari ro\u2018yxati, xaridlar va aksiyalarni tez rejalash uchun\r\nPul qoldiqlari \u2014 kassalar bo\u2018yicha joriy balanslar\r\nSotuv va Mijoz to\u2019lovlari grafiki \u2014 tanlangan davr uchun savdo grafiklari, ishlar qanday ketayotganini tez baholash uchun\r\nO\u2018tish uchun ekran yuqori chap burchagidagi Bosh Panel tugmasini bosing.\r\nDashing\r\nMaslahatBosh Panel aniq ma\u2019lumotlarni ko\u2018rsatishi uchun uning sozlamalarini tushunish muhim. Bosh Panel haqida batafsil bilish va uni biznesingizga moslab sozlash uchun tegishli yo\u2018riqnomani ko\u2018ring."'})]})}function d(a={}){const{wrapper:i}={...(0,o.R)(),...a.components};return i?(0,l.jsx)(i,{...a,children:(0,l.jsx)(m,{...a})}):m(a)}},8453:(a,i,n)=>{n.d(i,{R:()=>s,x:()=>t});var r=n(6540);const l={},o=r.createContext(l);function s(a){const i=r.useContext(o);return r.useMemo(function(){return"function"==typeof a?a(i):{...i,...a}},[i,a])}function t(a){let i;return i=a.disableParentContext?"function"==typeof a.components?a.components(l):a.components||l:s(a.components),r.createElement(o.Provider,{value:i},a.children)}}}]);